ops['CompanySignedDate'] = pd.to_datetime(ops['CompanySignedDate'])
ops['cycle_days'] = (ops['CompanySignedDate'] - ops['OppCreatedDate']).dt.days
agg = ops.groupby('AgentId', as_index=False)['cycle_days'].mean()
